import{d as a}from"./index-CjyuK5MW.js";class p{async createOrder(e){return(await a.post("/paypal/init",e)).data}async captureOrder(e){return(await a.post("/paypal/capture",e)).data}async getOrderDetails(e){return(await a.get(`/paypal/order/${e}`)).data}getApprovalUrl(e){var s;const r=(s=e.links)==null?void 0:s.find(t=>t.rel==="approve");return(r==null?void 0:r.href)||null}}const c=new p;export{c as p};
